const items = $input.all();

let userProfile = null;
const topicWeights = [];

for (const item of items) {
  const fields = item.json.fields || item.json;

  // If it has user_id → it's the profile
  if (fields.user_id) {
    userProfile = fields;
  }
  // If it has topic but no user_id → it's a topic weight row
  else if (fields.topic) {
    topicWeights.push(fields);
  }
}

const memoryPackage = {
  user_profile: userProfile,
  topic_weights: topicWeights,
  generated_at: new Date().toISOString()
};

return [{ json: memoryPackage }];

const raw = $input.first().json.output[0].content[0].text;

const cleaned = raw
  .replace(/^```json\s*/i, '')
  .replace(/```\s*$/,'')
  .trim();

const parsed = JSON.parse(cleaned);

return { json: parsed };

const brief = $input.first().json;

const messages = [
  {
    role: "system",
    content: `You are a Scout Agent for an AI PM learning system.
Your user is an early-stage AI PM preparing for FAANG interviews. They want practical, easy to digest content — NOT heavy academic papers.
Prioritise in this order:
1. Project walkthroughs — developers building real products with AI tools
2. Opinion pieces — takes on where AI is heading, what PMs should know
3. Interview prep — candidates sharing their OpenAI/Anthropic/FAANG interview experience, questions asked, how to prepare
4. News — product launches, funding, industry moves
5. Academic papers — only if they have a clear practical application
Your tools:
- search_hackernews: Search HackerNews for AI news, projects, discussions
- fetch_rss: Fetch articles from RSS feeds
- search_arxiv: Use sparingly, only for breakthrough practical releases
Strategy:
1. Call search_hackernews for primary topics + "built with" or "interview experience"
2. Call fetch_rss for preferred sources
3. Return ONLY 2 best articles — not 3, not 5. Just the 2 most relevant and practical ones.
Return format when done:
{
  "articles": [
    {
      "title": "...",
      "url": "...",
      "source": "...",
      "topic": "...",
      "summary": "..."
    }
  ]
}`
  },
  {
    role: "user",
    content: `Here is today's search brief: ${JSON.stringify(brief.search_brief)}`
  }
];

const tools = [
  {
    type: "function",
    function: {
      name: "search_arxiv",
      description: "Search arXiv for recent AI research papers. Use sparingly, only for breakthrough practical releases.",
      parameters: {
        type: "object",
        properties: {
          query: { type: "string", description: "Search query" },
          max_results: { type: "integer", description: "Number of results to return", default: 5 }
        },
        required: ["query"]
      }
    }
  },
  {
    type: "function",
    function: {
      name: "search_hackernews",
      description: "Search HackerNews for AI industry news, product launches, project walkthroughs, interview experiences.",
      parameters: {
        type: "object",
        properties: {
          query: { type: "string", description: "Search query" },
          limit: { type: "integer", description: "Number of results", default: 5 }
        },
        required: ["query"]
      }
    }
  },
  {
    type: "function",
    function: {
      name: "fetch_rss",
      description: "Fetch articles from an RSS feed.",
      parameters: {
        type: "object",
        properties: {
          feed_url: { type: "string", description: "Full RSS feed URL" },
          limit: { type: "integer", description: "Number of articles to return", default: 3 }
        },
        required: ["feed_url"]
      }
    }
  }
];

return [{ 
  json: { 
    messages,
    tools,
    search_brief: brief.search_brief,
    run_manifest: brief.run_manifest
  } 
}];

const response = $input.first().json;

// Get all tool calls GPT-4o wants to make
const toolCalls = response.choices[0].message.tool_calls;

// Get the full messages array from earlier in the workflow
const existingMessages = $input.first().json;

// Format each tool call as a separate item
return toolCalls.map(toolCall => ({
  json: {
    tool_call_id: toolCall.id,
    tool_name: toolCall.function.name,
    tool_arguments: JSON.parse(toolCall.function.arguments),
    // Pass the full response so we can build message history later
    full_response: response
  }
}));

const item = $input.first().json;

// Validated RSS URL lookup table
const RSS_URLS = {
  "lenny newsletter": "https://www.lennysnewsletter.com/feed",
  "lenny's newsletter": "https://www.lennysnewsletter.com/feed",
  "stratechery": "https://stratechery.com/feed",
  "the product compass": "https://www.theproductcompass.com/feed",
  "aakash gupta": "https://aakashg.substack.com/feed",
  "import ai": "https://importai.substack.com/feed",
  "the batch": "https://www.deeplearning.ai/the-batch/feed/",
  "tldr ai": "https://tldr.tech/ai/rss",
  "latent space": "https://www.latent.space/feed"
};

// Get the feed_url GPT-4o requested
const requestedUrl = item.tool_arguments.feed_url || "";
const requestedSource = item.tool_arguments.source_name || "";

// Try to match against our lookup table
let resolvedUrl = requestedUrl;

for (const [key, url] of Object.entries(RSS_URLS)) {
  if (requestedUrl.toLowerCase().includes(key) || 
      requestedSource.toLowerCase().includes(key)) {
    resolvedUrl = url;
    break;
  }
}

// If URL looks wrong (no lennysnewsletter, no stratechery etc) use default
const validDomains = ['lennysnewsletter', 'stratechery', 'theproductcompass', 
                       'aakashg', 'importai', 'deeplearning', 'tldr', 'latent'];
const isValidUrl = validDomains.some(domain => resolvedUrl.includes(domain));

if (!isValidUrl) {
  // Default to Lenny if URL is unrecognized
  resolvedUrl = "https://www.lennysnewsletter.com/feed";
}

return [{ 
  json: { 
    ...item,
    tool_arguments: {
      ...item.tool_arguments,
      feed_url: resolvedUrl
    }
  } 
}];

const items = $input.all();
let allArticles = [];
items.forEach((item, index) => {
  const data = item.json;
  if (data.hits) {
    data.hits.forEach(h => {
      if (h.title) allArticles.push({
        title: h.title,
        url: h.url || (h.objectID ? `https://news.ycombinator.com/item?id=${h.objectID}` : ''),
        source: 'HackerNews',
        summary: h.story_text || h.comment_text || ''
      });
    });
  } else if (data.data && typeof data.data === 'string') {
    const entries = data.data.match(/<entry>([\s\S]*?)<\/entry>/g) || [];
    entries.forEach(entry => {
      const title   = (entry.match(/<title>([\s\S]*?)<\/title>/)    || [])[1] || '';
      const summary = (entry.match(/<summary>([\s\S]*?)<\/summary>/) || [])[1] || '';
      const link    = (entry.match(/<id>([\s\S]*?)<\/id>/)           || [])[1] || '';
      if (title) allArticles.push({
        title: title.trim(),
        url: link.trim(),
        source: 'arXiv',
        summary: summary.trim().substring(0, 300)
      });
    });
  } else {
    const rssItems = data.data
      ? (data.data.match(/<item>([\s\S]*?)<\/item>/g) || [])
      : [];
    rssItems.forEach(rssItem => {
      const title = (rssItem.match(/<title><!\[CDATA\[(.*?)\]\]><\/title>/) ||
                     rssItem.match(/<title>(.*?)<\/title>/) || [])[1] || '';
      const link  = (rssItem.match(/<link>(.*?)<\/link>/) || [])[1] || '';
      const desc  = (rssItem.match(/<description><!\[CDATA\[(.*?)\]\]><\/description>/) ||
                     rssItem.match(/<description>(.*?)<\/description>/) || [])[1] || '';
      if (title) allArticles.push({
        title: title.trim(),
        url: link.trim(),
        source: 'RSS',
        summary: desc.replace(/<[^>]+>/g, '').trim().substring(0, 300)
      });
    });
  }
});

const articleList = allArticles.map((a, i) =>
  `Article ${i+1}:
Title: ${a.title}
URL: ${a.url}
Source: ${a.source}
Summary: ${a.summary}`
).join('\n\n');

const payload = JSON.stringify({
  model: "gpt-4o",
  messages: [
    {
      role: "system",
      content: `You are a Ranker Agent for an AI PM learning system.
Given a list of articles, select the TOP 2 most relevant for an AI PM targeting FAANG.
Prefer: project walkthroughs, opinion pieces, interview experiences, product news.
Avoid: academic papers, deep technical content, anything with code.
Score each on relevance (1-10) and explain why.
Return ONLY 2 articles. Return ONLY valid JSON: {"ranked_articles": [{"title": "...", "url": "...", "source": "...", "topic": "...", "summary": "...", "score": 9, "reason": "..."}]}`
    },
    {
      role: "user",
      content: `Rank these articles for an AI PM targeting FAANG in NYC:\n\n${articleList}`
    }
  ]
});

return [{ json: { 
  payload, 
  article_count: allArticles.length,
  run_manifest: $('Code in JavaScript2').first().json.run_manifest
} }];

// Pass payload string through for HTTP Request5 to send raw
const { payload } = $input.first().json;
return [{ json: { payload } }];

const items = $input.all();
const response = items[0].json;

// GPT-4o answered directly without tool calls
