const response = $input.first().json;
const content = response.choices[0].message.content;

let ranked_articles = [];
try {
  const jsonMatch = content.match(/```json\n?([\s\S]*?)\n?```/);
  const cleaned = jsonMatch ? jsonMatch[1] : content;
  const parsed = JSON.parse(cleaned);
  ranked_articles = parsed.ranked_articles || [];
} catch(e) {
  ranked_articles = [];
}

return [{ json: { ranked_articles, count: ranked_articles.length } }];

const { ranked_articles } = $input.first().json;

const articleList = ranked_articles.map((a, i) =>
  `Article ${i+1}:
Title: ${a.title}
URL: ${a.url}
Source: ${a.source}
Topic: ${a.topic}
Summary: ${a.summary}`
).join('\n\n');

const payload = JSON.stringify({
  model: "gpt-4o",
  messages: [
    {
      role: "system",
      content: `You are an Explainer Agent for an AI PM learning system. 
For each article, write a PM-focused brief with exactly these 4 fields:
1. tldr: 2 sentence plain English summary
2. why_it_matters: 1 sentence — why an AI PM at FAANG should care
3. key_term: one technical term explained simply in 1 sentence
4. product_opportunity: one product idea this article inspires

Return ONLY valid JSON: {"explained_articles": [{"title": "...", "url": "...", "tldr": "...", "why_it_matters": "...", "key_term": "...", "product_opportunity": "..."}]}`
    },
    {
      role: "user",
      content: `User is an AI PM targeting FAANG in NYC.\n\nArticles:\n${articleList}`
    }
  ]
});

return [{ json: { payload, ranked_articles } }];

const response = $input.first().json;
const content = response.choices[0].message.content;

let explained_articles = [];
try {
  const jsonMatch = content.match(/```json\n?([\s\S]*?)\n?```/);
  const cleaned = jsonMatch ? jsonMatch[1] : content;
  const parsed = JSON.parse(cleaned);
  explained_articles = parsed.explained_articles || [];
} catch(e) {
  explained_articles = [];
}

return [{ json: { explained_articles, count: explained_articles.length } }];

const { explained_articles } = $input.first().json;

const articleList = explained_articles.map((a, i) =>
  `Article ${i+1}: ${a.title}\nTLDR: ${a.tldr}\nWhy it matters: ${a.why_it_matters}`
).join('\n\n');

const payload = JSON.stringify({
  model: "gpt-4o",
  messages: [
    {
      role: "system",
      content: `You are a Quiz Agent for an AI PM learning system. For each article generate 3 questions:
1. Factual: what happened/was released?
2. Application: how would you use this in a product?
3. Opinion: what is the biggest risk or opportunity?
Return ONLY valid JSON: {"quizzes": [{"title": "...", "questions": ["q1", "q2", "q3"], "model_answers": ["a1", "a2", "a3"]}]}`
    },
    {
      role: "user",
      content: `Generate quiz questions for these articles:\n\n${articleList}`
    }
  ]
});

return [{ json: { payload, explained_articles } }];

const response = $input.first().json;
const content = response.choices[0].message.content;
let quizzes = [];

try {
  const jsonMatch = content.match(/```json\n?([\s\S]*?)\n?```/);
  const cleaned = jsonMatch ? jsonMatch[1] : content;
  const parsed = JSON.parse(cleaned);
  quizzes = parsed.quizzes || [];
} catch(e) {
  quizzes = [];
}

// Extract flat arrays across all quizzes
const quiz_questions = quizzes.flatMap(q => q.questions || []);
const correct_answers = quizzes.flatMap(q => q.model_answers || []);

const explained_articles = $('Code in JavaScript11').first().json.explained_articles || [];

const payload = JSON.stringify({
  model: "gpt-4o",
  messages: [{ role: "user", content: "Say OK" }],
  max_tokens: 5
});

return [{ json: { quizzes, quiz_questions, correct_answers, explained_articles, payload } }];

const { quizzes, explained_articles } = $input.first().json;
const ranked_articles = $('Code in JavaScript8').first().json.ranked_articles;

const records = ranked_articles.map((article, i) => {
  const explained = explained_articles[i] || {};
  const quiz = quizzes[i] || {};

  return {
    json: {
      title: article.title,
      url: article.url,
      source: article.source,
      date_fetched: new Date().toISOString(),
      date_delivered: new Date().toISOString(),
      relevance_score: article.score,
      signal_quality_score: article.score,
      summary: article.summary,
      why_it_matters: explained.why_it_matters || '',
      quiz_questions: JSON.stringify(quiz.questions || []),
      quiz_model_answers: JSON.stringify(quiz.model_answers || []),
      topic_tags: article.topic,
      status: 'delivered'
    }
  };
});

return records;
